/* ── Feature Detail Modal ── */
const FeatureModal = ({ feature, onClose }) => {
    if (!feature) return null;
    return (
        <div
            style={{
                position: 'fixed', inset: 0, zIndex: 1000,
                background: 'rgba(0,0,0,0.58)',
                backdropFilter: 'blur(5px)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                padding: 20, overflowY: 'auto',
            }}
            onClick={onClose}
        >
            <div
                style={{
                    background: '#fff', borderRadius: 24,
                    maxWidth: 800, width: '100%',
                    maxHeight: '92vh', overflowY: 'auto',
                    boxShadow: '0 32px 80px rgba(0,0,0,0.28)',
                    fontFamily: FONT,
                }}
                onClick={e => e.stopPropagation()}
            >
                {/* Hero photo */}
                <div style={{ width: '100%', height: 280, position: 'relative', borderRadius: '24px 24px 0 0', overflow: 'hidden' }}>
                    <img
                        src={feature.image}
                        alt={feature.title}
                        style={{ width: '100%', height: '100%', objectFit: 'cover', objectPosition: 'center' }}
                    />
                    <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top,rgba(0,0,0,0.60) 0%,rgba(0,0,0,0.10) 55%,transparent 100%)' }} />

                    {/* Close */}
                    <button onClick={onClose} style={{
                        position: 'absolute', top: 14, right: 14,
                        width: 36, height: 36, borderRadius: '50%',
                        background: 'rgba(255,255,255,0.92)', border: 'none',
                        cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
                        boxShadow: '0 2px 10px rgba(0,0,0,0.18)',
                    }}>
                        <FiX size={17} style={{ color: '#1c1917' }} />
                    </button>

                    {/* Feature title on image */}
                    <div style={{ position: 'absolute', bottom: 20, left: 24 }}>
                        <div style={{
                            display: 'inline-flex', alignItems: 'center', gap: 8,
                            background: 'linear-gradient(135deg,#f97316,#ea580c)',
                            borderRadius: 10, padding: '7px 15px',
                            color: '#fff', fontSize: 13, fontWeight: 700,
                        }}>
                            {feature.icon} {feature.title}
                        </div>
                    </div>
                </div>

                {/* Body */}
                <div style={{ padding: '28px 32px 36px' }}>
                    <h2 style={{ fontSize: 22, fontWeight: 800, color: '#1c1917', marginBottom: 18, lineHeight: 1.3 }}>
                        {feature.detail.headline}
                    </h2>

                    {feature.detail.body.split('\n\n').map((para, i) => (
                        <p key={i} style={{ color: '#57534e', fontSize: 14.5, lineHeight: 1.8, marginBottom: 14 }}>{para}</p>
                    ))}

                    {/* Stats */}
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 12, margin: '26px 0' }}>
                        {feature.detail.stats.map((s, i) => (
                            <div key={i} style={{
                                background: '#fff7ed', borderRadius: 14,
                                padding: '16px 12px', textAlign: 'center',
                                border: '1.5px solid #fed7aa',
                            }}>
                                <div style={{ fontSize: 24, fontWeight: 800, color: '#f97316' }}>{s.value}</div>
                                <div style={{ fontSize: 11, color: '#78716c', marginTop: 5, fontWeight: 500, lineHeight: 1.4 }}>{s.label}</div>
                            </div>
                        ))}
                    </div>

                    {/* Highlights */}
                    <div style={{ background: '#fafaf9', borderRadius: 14, padding: '18px 22px', border: '1px solid #e7e5e4' }}>
                        <div style={{ fontSize: 11, fontWeight: 700, color: '#f97316', letterSpacing: 1.5, textTransform: 'uppercase', marginBottom: 14 }}>Key Highlights</div>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                            {feature.detail.highlights.map((h, i) => (
                                <div key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 8 }}>
                                    <FiChevronRight size={13} style={{ color: '#f97316', flexShrink: 0, marginTop: 2 }} />
                                    <span style={{ fontSize: 13, color: '#44403c', lineHeight: 1.5 }}>{h}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* CTA */}
                    <div style={{ marginTop: 26, display: 'flex', justifyContent: 'flex-end' }}>
                        <Link to="/Booking" onClick={onClose} style={{ textDecoration: 'none' }}>
                            <button style={{
                                display: 'inline-flex', alignItems: 'center', gap: 8,
                                padding: '12px 26px', borderRadius: 12,
                                background: 'linear-gradient(135deg,#f97316,#ea580c)',
                                color: '#fff', border: 'none', fontSize: 14, fontWeight: 700,
                                cursor: 'pointer', fontFamily: FONT,
                                boxShadow: '0 4px 16px rgba(249,115,22,0.30)',
                                transition: 'transform 0.18s',
                            }}
                                onMouseEnter={e => e.currentTarget.style.transform = 'translateY(-2px)'}
                                onMouseLeave={e => e.currentTarget.style.transform = 'none'}
                            >
                                <FiCalendar size={15} /> Book Darshan Now <FiArrowRight size={14} />
                            </button>
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
};

